INSERT IGNORE INTO `t_article` (`id`, `title`, `summary`, `content`, `department_id`, `author`, `image`, `views`, `status`, `publish_time`, `create_time`, `update_time`) VALUES
(1, '冠心病的预防与治疗', '冠心病是冠状动脉粥样硬化性心脏病，是冠状动脉血管发生动脉粥样硬化病变而引起血管腔狭窄或阻塞，造成心肌缺血、缺氧或坏死而导致的心脏病。', '<p>冠心病是冠状动脉粥样硬化性心脏病，是冠状动脉血管发生动脉粥样硬化病变而引起血管腔狭窄或阻塞，造成心肌缺血、缺氧或坏死而导致的心脏病。</p>', 11, '健康顾问', 'img/health_01.jpeg', 2356, 1, '2024-03-15 00:00:00', '2024-03-15 00:00:00', '2024-03-15 00:00:00'),
(2, '高血压患者的日常饮食注意事项', '高血压是一种常见的慢性病，合理的饮食对于控制血压至关重要。本文详细介绍高血压患者的饮食原则和禁忌，帮助您科学管理血压。', '<p>高血压是一种常见的慢性疾病，合理的饮食对于控制血压至关重要。</p>', 11, '心内科专家', 'img/health_02.jpeg', 1890, 1, '2024-03-14 00:00:00', '2024-03-14 00:00:00', '2024-03-14 00:00:00'),
(3, '慢性支气管炎的防治', '慢性支气管炎是气管、支气管黏膜及其周围组织的慢性非特异性炎症，临床上以长期咳嗽、咳痰或伴有喘息为主要特征。', '<p>慢性支气管炎是气管、支气管黏膜及其周围组织的慢性非特异性炎症。</p>', 12, '呼吸内科专家', 'img/health_03.jpeg', 3201, 1, '2024-03-13 00:00:00', '2024-03-13 00:00:00', '2024-03-13 00:00:00'),
(4, '颈椎病的康复治疗', '长时间坐在电脑前工作的上班族，颈椎健康问题日益突出。本文为您介绍简单有效的颈椎保健方法和日常锻炼建议。', '<p>长时间坐在电脑前工作的上班族，颈椎健康问题日益突出。</p>', 22, '骨科专家', 'img/health_01.jpeg', 4521, 1, '2024-03-12 00:00:00', '2024-03-12 00:00:00', '2024-03-12 00:00:00'),
(5, '胃溃疡的饮食调理', '胃黏膜发生的炎性缺损，病变穿透黏膜肌层，常发生于胃角、胃窦小弯和胃体小弯。本文介绍胃溃疡的饮食调理方法。', '<p>胃黏膜发生的炎性缺损，病变穿透黏膜肌层。</p>', 13, '消化内科专家', 'img/health_02.jpeg', 1567, 1, '2024-03-11 00:00:00', '2024-03-11 00:00:00', '2024-03-11 00:00:00'),
(6, '如何改善睡眠质量', '睡眠质量直接影响身体健康和工作效率。本文介绍几种科学改善睡眠的方法，帮助您拥有更好的睡眠。', '<p>睡眠质量直接影响身体健康和工作效率。</p>', 61, '神经内科专家', 'img/health_03.jpeg', 2876, 1, '2024-03-10 00:00:00', '2024-03-10 00:00:00', '2024-03-10 00:00:00'),
(7, '糖尿病患者饮食指南', '糖尿病是一组以高血糖为特征的代谢性疾病，饮食控制是糖尿病治疗的基础。本文详细介绍糖尿病患者的饮食原则。', '<p>糖尿病是一组以高血糖为特征的代谢性疾病。</p>', 15, '内分泌科专家', 'img/health_01.jpeg', 1987, 1, '2024-03-09 00:00:00', '2024-03-09 00:00:00', '2024-03-09 00:00:00'),
(8, '小儿肺炎的预防与护理', '儿童时期常见的呼吸道感染性疾病，是导致儿童死亡的主要原因之一。本文介绍小儿肺炎的预防与护理方法。', '<p>儿童时期常见的呼吸道感染性疾病。</p>', 41, '儿科专家', 'img/health_02.jpeg', 2134, 1, '2024-03-08 00:00:00', '2024-03-08 00:00:00', '2024-03-08 00:00:00'),
(9, '办公室视力保护小妙招', '长时间盯着电脑屏幕，容易导致视力下降。本文分享几个简单有效的视力保护方法。', '<p>长时间盯着电脑屏幕，容易导致视力下降。</p>', 81, '眼科医生', 'img/health_03.jpeg', 1654, 1, '2024-03-07 00:00:00', '2024-03-07 00:00:00', '2024-03-07 00:00:00'),
(10, '秋冬季节如何预防感冒', '秋冬季节是感冒的高发期，了解感冒的预防措施对保护自己和家人健康很重要。', '<p>秋冬季节是感冒的高发期。</p>', 12, '呼吸内科专家', 'img/health_01.jpeg', 3421, 1, '2024-03-06 00:00:00', '2024-03-06 00:00:00', '2024-03-06 00:00:00'),
(11, '妇科常见疾病的预防', '妇科常见疾病包括子宫肌瘤、宫颈癌等，了解预防措施对女性健康至关重要。', '<p>妇科常见疾病包括子宫肌瘤、宫颈癌等。</p>', 31, '妇科专家', 'img/health_02.jpeg', 2087, 1, '2024-03-05 00:00:00', '2024-03-05 00:00:00', '2024-03-05 00:00:00'),
(12, '皮肤过敏的防治方法', '皮肤过敏是一种常见的皮肤病，了解过敏原和防治方法有助于保持皮肤健康。', '<p>皮肤过敏是一种常见的皮肤病。</p>', 71, '皮肤科专家', 'img/health_03.jpeg', 2567, 1, '2024-03-04 00:00:00', '2024-03-04 00:00:00', '2024-03-04 00:00:00');